@ARTICLE{10.1016/j.addr.2021.114021,
	author = {Lee Y and Kamada N and Moon JJ},
	title = {Oral nanomedicine for modulating immunity, intestinal barrier functions, and gut microbiome.},
	journal = {Adv Drug Deliv Rev},
	year = {2021},
	abstract = {The gastrointestinal tract (GIT) affects not only local diseases in the GIT but also various systemic diseases. Factors that can affect the health and disease of both GIT and the human body include 1) the mucosal immune system composed of the gut-associated lymphoid tissues and the lamina propria, 2) the intestinal barrier composed of mucus and intestinal epithelium, and 3) the gut microbiota. Selective delivery of drugs, including antigens, immune-modulators, intestinal barrier enhancers, and gut-microbiome manipulators, has shown promising results for oral vaccines, immune tolerance, treatment of inflammatory bowel diseases, and other systemic diseases, including cancer. However, physicochemical and biological barriers of the GIT present significant challenges for successful translation. With the advances of novel nanomaterials, oral nanomedicine has emerged as an attractive option to not only overcome these barriers but also to selectively deliver drugs to the target sites in GIT. In this review, we discuss the GIT factors and physicochemical and biological barriers in the GIT. Furthermore, we present the recent progress of oral nanomedicine for oral vaccines, immune tolerance, and anti-inflammation therapies. We also discuss recent advances in oral nanomedicine designed to fortify the intestinal barrier functions and modulate the gut microbiota and microbial metabolites. Finally, we opine about the future directions of oral nano-immunotherapy.},
	doi = {10.1016/j.addr.2021.114021},
	pmid = {34710529 [Indexed for MEDLINE]},
	note = {PMC8665886}
}

@ARTICLE{10.1016/j.biomaterials.2021.121178,
	author = {Zu M and Xie D and Canup BSB and Chen N and Wang Y and Sun R and Zhang Z and Fu Y and Dai F and Xiao B},
	title = {'Green' nanotherapeutics from tea leaves for orally targeted prevention and alleviation of colon diseases.},
	journal = {Biomaterials},
	year = {2021},
	abstract = {Although synthesized nanotherapeutics (NTs) are attractive for the oral treatment of colon diseases, their clinical translations are constrained by the unsatisfactory therapeutic outcomes, potential adverse effects, and high cost of mass production. Here, we report the development of tea leaf-derived natural NTs with desirable particle sizes (140.0 nm) and negative surface charge (-14.6 mV). These natural exosome-like NTs were found to contain large amounts of lipids, some functional proteins, and many bioactive small molecules. Specifically, galactose groups on the surface of NTs could mediate their specific internalization by macrophages via galactose receptor-mediated endocytosis. Moreover, these NTs were able to reduce the production of reactive oxygen species, inhibit the expression of pro-inflammatory cytokines, and increase the amount of anti-inflammatory IL-10 secreted by macrophages. Orally administered NTs could efficiently inhibit the inflammatory bowel responses, restore disrupted colonic barriers and enhance the diversity and overall abundance of gut microbiota, thereby preventing or alleviating inflammatory bowel disease and colitis-associated colon cancer. The present study brings new insights to the facile application of a versatile and robust natural nanoplatform for the prevention and treatment of colon diseases.},
	doi = {10.1016/j.biomaterials.2021.121178},
	pmid = {34656857 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/molecules26113301,
	author = {Jiang Y and Jiang Z and Ma L and Huang Q},
	title = {Advances in Nanodelivery of Green Tea Catechins to Enhance the Anticancer Activity.},
	journal = {Molecules},
	year = {2021},
	abstract = {Cancer is one of the leading causes of death globally. A variety of phenolic compounds display preventative and therapeutic effects against cancers. Green teas are rich in phenolics. Catechins are the most dominant phenolic component in green teas. Studies have shown that catechins have anticancer activity in various cancer models. The anticancer activity of catechins, however, may be compromised due to their low oral bioavailability. Nanodelivery emerges as a promising way to improve the oral bioavailability and anticancer activity of catechins. Research in this area has been actively conducted in recent decades. This review provides the molecular mechanisms of the anticancer effects of catechins, the factors that limit the oral bioavailability of catechins, and the latest advances of delivering catechins using nanodelivery systems through different routes to enhance their anticancer activity.},
	doi = {10.3390/molecules26113301},
	pmid = {34072700 [Indexed for MEDLINE]},
	note = {PMC8198522}
}

@ARTICLE{10.3389/fimmu.2020.615240,
	author = {Cuzzubbo S and Mangsbo S and Nagarajan D and Habra K and Pockley AG and McArdle SEB},
	title = {Cancer Vaccines: Adjuvant Potency, Importance of Age, Lifestyle, and Treatments.},
	journal = {Front Immunol},
	year = {2021},
	abstract = {Although the discovery and characterization of multiple tumor antigens have sparked the development of many antigen/derived cancer vaccines, many are poorly immunogenic and thus, lack clinical efficacy. Adjuvants are therefore incorporated into vaccine formulations to trigger strong and long-lasting immune responses. Adjuvants have generally been classified into two categories: those that 'depot' antigens (e.g. mineral salts such as aluminum hydroxide, emulsions, liposomes) and those that act as immunostimulants (Toll Like Receptor agonists, saponins, cytokines). In addition, several novel technologies using vector-based delivery of antigens have been used. Unfortunately, the immune system declines with age, a phenomenon known as immunosenescence, and this is characterized by functional changes in both innate and adaptive cellular immunity systems as well as in lymph node architecture. While many of the immune functions decline over time, others paradoxically increase. Indeed, aging is known to be associated with a low level of chronic inflammation-inflamm-aging. Given that the median age of cancer diagnosis is 66 years and that immunotherapeutic interventions such as cancer vaccines are currently given in combination with or after other forms of treatments which themselves have immune-modulating potential such as surgery, chemotherapy and radiotherapy, the choice of adjuvants requires careful consideration in order to achieve the maximum immune response in a compromised environment. In addition, more clinical trials need to be performed to carefully assess how less conventional form of immune adjuvants, such as exercise, diet and psychological care which have all be shown to influence immune responses can be incorporated to improve the efficacy of cancer vaccines. In this review, adjuvants will be discussed with respect to the above-mentioned important elements.},
	doi = {10.3389/fimmu.2020.615240},
	pmid = {33679703 [Indexed for MEDLINE]},
	note = {PMC7927599}
}

@ARTICLE{10.1016/j.ejpb.2020.12.004,
	author = {Dos Santos AM and Meneguin AB and Akhter DT and Fletcher N and Houston ZH and Bell C and Thurecht KJ, Gremião MPD},
	title = {Understanding the role of colon-specific microparticles based on retrograded starch/pectin in the delivery of chitosan nanoparticles along the gastrointestinal tract.},
	journal = {Eur J Pharm Biopharm},
	year = {2021},
	abstract = {The encapsulation of nanoparticles within microparticles designed for specific delivery to the colon is a relevant strategy to avoid premature degradation or release of nanoparticles during their passage through the stomach and upper gastrointestinal tract (GIT), allowing the targeted delivery of chemotherapeutics to the colon after oral administration. Here, we designed an oral multiparticulate system to achieve targeted release in the colon. In this sense, chitosan nanoparticles (CS NPs) encapsulated with 5-fluorouracil (5-FU) and incorporated into retrograded starch and pectin (RS/P) microparticles were developed and their in vivo distribution along the mouse GIT after oral administration was monitored using multispectral optical imaging. In vitro release studies revealed that the encapsulation of CS NPs into RS/P microparticles promoted greater control of 5-FU release rates, with a significant reduction (53%) in acid media that might replicate that found in the stomach following oral administration. The evaluation of the in vivo biodistribution of the CS NPs in mice showed a faster clearance in the distribution pattern along the mouse GIT, i.e., a shorter transit time of CS NPs compared to CS NPs-loaded RS/P microparticles. Additionally, CS NPs alone showed non-specific absorption into the blood-stream with associated kidney accumulation, while for the CS NPs-loaded RS/P microparticles no significant accumulation was observed in blood or major clearance organs. This suggests the specific degradability of RS/P by the colon microbiota appears to have been decisive in the higher protection of the CS NPs along the GIT until release in the colon, preventing unwanted absorption into the bloodstream and major organs following oral administration. Our findings represent a proof of concept for the use of RS/P microparticles as potential carriers for delivering drug-loaded nanoparticles to the colon and this work will contribute to the development of oral-systems for colorectal cancer therapy.},
	doi = {10.1016/j.ejpb.2020.12.004},
	pmid = {33309846 [Indexed for MEDLINE]}
}
